class Solution:
    def minimumWeight(self, edges, queries):
        from collections import defaultdict, deque
        n = len(edges) + 1
        g = defaultdict(list)
        for u, v, w in edges:
            g[u].append((v, w))
            g[v].append((u, w))
        def dist(a, b):
            dq = deque([(a, 0)])
            seen = {a}
            while dq:
                x, d = dq.popleft()
                if x == b:
                    return d
                for y, w in g[x]:
                    if y not in seen:
                        seen.add(y)
                        dq.append((y, d + w))
            return -1
        out = []
        for s1, s2, dst in queries:
            out.append((dist(s1, s2) + dist(s2, dst) + dist(s1, dst)) // 2)
        return out

