class Solution:
    def minimumWeight(self, edges, queries):
        from collections import defaultdict, deque
        n = len(edges) + 1
        g = defaultdict(list)
        for u, v, w in edges:
            g[u].append((v, w))
            g[v].append((u, w))
        LOG = max(1, (n).bit_length())
        up = [[-1] * n for _ in range(LOG)]
        depth = [0] * n
        dw = [0] * n
        order = []
        dq = deque([0])
        seen = [False] * n
        seen[0] = True
        while dq:
            x = dq.popleft()
            order.append(x)
            for y, w in g[x]:
                if not seen[y]:
                    seen[y] = True
                    up[0][y] = x
                    depth[y] = depth[x] + 1
                    dw[y] = dw[x] + w
                    dq.append(y)
        for j in range(1, LOG):
            for i in range(n):
                if up[j-1][i] != -1:
                    up[j][i] = up[j-1][up[j-1][i]]
        def lca(a, b):
            if depth[a] < depth[b]:
                a, b = b, a
            diff = depth[a] - depth[b]
            for j in range(LOG):
                if (diff >> j) & 1:
                    a = up[j][a]
            if a == b:
                return a
            for j in range(LOG - 1, -1, -1):
                if up[j][a] != up[j][b]:
                    a = up[j][a]
                    b = up[j][b]
            return up[0][a]
        def dist(a, b):
            return dw[a] + dw[b] - 2 * dw[lca(a, b)]
        out = []
        for s1, s2, dst in queries:
            out.append((dist(s1, s2) + dist(s2, dst) + dist(s1, dst)) // 2)
        return out

