var minimumWeight = function(edges, queries) {
    const n = edges.length + 1;
    const g = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) { g[u].push([v, w]); g[v].push([u, w]); }
    const LOG = Math.max(1, 32 - Math.clz32(n));
    const up = Array.from({ length: LOG }, () => new Array(n).fill(-1));
    const depth = new Array(n).fill(0);
    const dw = new Array(n).fill(0);
    const seen = new Array(n).fill(false);
    const dq = [0]; let head = 0; seen[0] = true;
    while (head < dq.length) {
        const x = dq[head++];
        for (const [y, w] of g[x]) {
            if (!seen[y]) {
                seen[y] = true;
                up[0][y] = x;
                depth[y] = depth[x] + 1;
                dw[y] = dw[x] + w;
                dq.push(y);
            }
        }
    }
    for (let j = 1; j < LOG; j++)
        for (let i = 0; i < n; i++)
            if (up[j-1][i] !== -1) up[j][i] = up[j-1][up[j-1][i]];
    const lca = (a, b) => {
        if (depth[a] < depth[b]) { const t = a; a = b; b = t; }
        let diff = depth[a] - depth[b];
        for (let j = 0; j < LOG; j++) if ((diff >> j) & 1) a = up[j][a];
        if (a === b) return a;
        for (let j = LOG - 1; j >= 0; j--) if (up[j][a] !== up[j][b]) { a = up[j][a]; b = up[j][b]; }
        return up[0][a];
    };
    const dist = (a, b) => dw[a] + dw[b] - 2 * dw[lca(a, b)];
    const out = [];
    for (const [s1, s2, dst] of queries) {
        out.push((dist(s1, s2) + dist(s2, dst) + dist(s1, dst)) / 2);
    }
    return out;
};
